const result = $input.first().json;
let imageUrl = '';
try {
  if (result.data && result.data.resultJson) {
    const resultData = typeof result.data.resultJson === 'string' ? JSON.parse(result.data.resultJson) : result.data.resultJson;
    imageUrl = resultData.images?.[0]?.url || resultData.url || resultData.output?.[0] || resultData.result?.[0]?.url || '';
  } else if (result.data && result.data.info && result.data.info.resultUrls) {
    imageUrl = result.data.info.resultUrls[0];
  }
} catch(e) {
  imageUrl = 'ERROR: ' + e.message;
}
return [{ json: { image_url: imageUrl, image_source: 'generated', raw_response: JSON.stringify(result) } }];

// 대본의 7줄을 5개 세그먼트로 분할 (각 세그먼트 ≤15초)
const scriptData = $input.first().json;
const lines = scriptData.script.lines;

const segments = [
  { segment_id: 1, section: 'HOOK', text: lines.slice(0, 1).map(l => l.text).join(' '), est_seconds: lines[0] ? (lines[0].end_sec - lines[0].start_sec) : 3 },
  { segment_id: 2, section: 'PROBLEM', text: lines.slice(1, 2).map(l => l.text).join(' '), est_seconds: lines[1] ? (lines[1].end_sec - lines[1].start_sec) : 4 },
  { segment_id: 3, section: 'DISCOVERY', text: lines.slice(2, 4).map(l => l.text).join(' '), est_seconds: lines[3] ? (lines[3].end_sec - lines[2].start_sec) : 5 },
  { segment_id: 4, section: 'SOLUTION', text: lines.slice(4, 6).map(l => l.text).join(' '), est_seconds: lines[5] ? (lines[5].end_sec - lines[4].start_sec) : 9 },
  { segment_id: 5, section: 'CTA', text: lines.slice(6, 7).map(l => l.text).join(' '), est_seconds: lines[6] ? (lines[6].end_sec - lines[6].start_sec) : 6 }
].filter(s => s.text.length > 0);

return segments.map(seg => ({
  json: {
    ...seg,
    brand: scriptData.brand,
    product: scriptData.product,
    model_image_url: scriptData.model_image_url
  }
}));

const result = $input.first().json;
const segData = $('TTS 세그먼트 순차 루프').first().json;
let audioUrl = '';
try {
  const tmpUrl = result.data?.url || result.url || '';
  audioUrl = tmpUrl.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
} catch(e) {
  audioUrl = 'ERROR: ' + e.message;
}
return [{ json: { audio_url: audioUrl, segment_id: segData.segment_id, section: segData.section, text: segData.text } }];

// 이미지 URL(1개) + 세그먼트 오디오 URL(5개)을 결합
// Merge 노드에서 combineAll로 들어오면 모든 조합이 생기므로
// 이미지 URL을 추출하고 세그먼트별로 정리
const items = $input.all();
const imageUrl = items[0]?.json?.image_url || '';

// 세그먼트별 오디오 URL 수집 (중복 제거)
const seen = new Set();
const segments = [];
for (const item of items) {
  const segId = item.json.segment_id;
  if (segId && !seen.has(segId)) {
    seen.add(segId);
    segments.push({
      segment_id: segId,
      section: item.json.section,
      audio_url: item.json.audio_url,
      image_url: imageUrl
    });
  }
}

// segment_id 순으로 정렬
segments.sort((a, b) => a.segment_id - b.segment_id);

return segments.map(seg => ({ json: seg }));

